{
  "activity": "Notebook",
  "name": "Run Silver Transformation",
  "notebook": "nb_transform_meters",
  "lakehouse": "lh_meter_readings",
  "parameters": {
    "processing_date": {
      "type": "string",
      "value": "@formatDateTime(utcNow(), 'yyyy-MM-dd')"
    }
  },
  "timeout": "01:00:00",
  "retryCount": 1,
  "retryInterval": 300
}

{
  "expressions": {
    "today_date": "@formatDateTime(utcNow(), 'yyyy-MM-dd')",
    "year_folder": "@formatDateTime(utcNow(), 'yyyy')",
    "month_folder": "@formatDateTime(utcNow(), 'MM')",
    "day_folder": "@formatDateTime(utcNow(), 'dd')",
    "full_path": "@concat('meter_exports/', formatDateTime(utcNow(), 'yyyy'), '/', formatDateTime(utcNow(), 'MM'), '/', formatDateTime(utcNow(), 'dd'), '/')",
    "param_ref": "@pipeline().parameters.processing_date",
    "yesterday": "@formatDateTime(adddays(utcNow(), -1), 'yyyy-MM-dd')"
  }
}

// M code generated by the Power Query Editor for NordGrid's substation dataflow
// Each step corresponds to one entry in the Applied Steps pane

let
    // Step 1: Connect to the Azure SQL Database
    Source = Sql.Database("nordgrid-db.database.windows.net", "substations_db"),

    // Step 2: Navigate to the substations table
    Navigation = Source{[Schema="dbo", Item="substations"]}[Data],

    // Step 3: Filter out inactive substations
    FilteredRows = Table.SelectRows(Navigation, each [status] <> "INACTIVE"),

    // Step 4: Remove vendor-specific columns
    RemovedColumns = Table.RemoveColumns(FilteredRows, {"audit_date", "vendor_code"}),

    // Step 5: Rename columns to match Silver schema
    RenamedColumns = Table.RenameColumns(RemovedColumns, {
        {"sub_id", "substation_id"},
        {"cap_mw", "capacity_mw"}
    }),

    // Step 6: Change capacity type from integer to decimal
    ChangedType = Table.TransformColumnTypes(RenamedColumns, {{"capacity_mw", type number}})
in
    ChangedType  // The final step's result is the dataflow's output
